// Sensör verilerini parse et
const mqttData = $input.first().json;

// Topic: enocart/session/{sessionId}/sensors
const topicParts = mqttData.topic?.split('/') || [];
const sessionId = topicParts[2] || mqttData.sessionId;

const sensorData = {
  sessionId,
  timestamp: mqttData.timestamp || new Date().toISOString(),
  barcode: mqttData.barcode,
  weight: mqttData.weight || 0, // gram
  scanInterval: mqttData.scanInterval || 0, // ms
  cameraEvent: mqttData.cameraEvent,
  productsScanned: mqttData.productsScanned || [],
  sessionDuration: mqttData.sessionDuration || 0, // sn
  paymentMethod: mqttData.paymentMethod,
  customerId: mqttData.customerId
};

return [{ json: sensorData }];

// Anomali tespiti
const data = $input.first().json;

const anomalies = [];

// 1. Ağırlık uyuşmazlığı (ürün beklenen ağırlık ile tarama anı ağırlık farkı)
if (data.expectedWeight && data.weight) {
  const weightDiff = Math.abs(data.weight - data.expectedWeight);
  if (weightDiff > 50) { // 50g tolerans
    anomalies.push({
      type: 'WEIGHT_MISMATCH',
      severity: 'HIGH',
      confidence: 0.85,
      details: `Beklenen: ${data.expectedWeight}g, Tarama: ${data.weight}g, Fark: ${weightDiff}g`,
      description: 'Ağırlık uyuşmazlığı tespit edildi'
    });
  }
}

// 2. Hızlı tarama (normalde ürün başı ~3-5 saniye)
if (data.scanInterval < 1500) { // 1.5 sn'den az
  anomalies.push({
    type: 'FAST_SCANNING',
    severity: 'MEDIUM',
    confidence: 0.7,
    details: `Tarama aralığı: ${data.scanInterval}ms`,
    description: 'Normalden çok hızlı tarama'
  });
}

// 3. Ardışık tarama atlaması (barkod okutulmadan geçme)
if (data.scannedCount && data.physicalCount) {
  const missRate = (data.physicalCount - data.scannedCount) / data.physicalCount;
  if (missRate > 0.15) { // %15'ten fazla kaçırma
    anomalies.push({
      type: 'SCAN_SKIP',
      severity: 'HIGH',
      confidence: 0.9,
      details: `Taranan: ${data.scannedCount}, Fiziksel: ${data.physicalCount}`,
      description: 'Çok sayıda ürün taranmadan geçilmiş'
    });
  }
}

// 4. Bilinmeyen ürün (sistemde kayıtlı olmayan barkod)
if (data.unknownBarcodes && data.unknownBarcodes.length > 0) {
  anomalies.push({
    type: 'UNKNOWN_PRODUCT',
    severity: 'MEDIUM',
    confidence: 0.6,
    details: `Bilinmeyen barkodlar: ${data.unknownBarcodes.join(', ')}`,
    description: 'Sistemde kayıtlı olmayan ürün tespit edildi'
  });
}

// 5. Şüpheli pozisyon (kamera analizi)
if (data.cameraAlert) {
  anomalies.push({
    type: 'POSITION_ALERT',
    severity: 'HIGH',
    confidence: 0.8,
    details: data.cameraAlert,
    description: 'Şüpheli pozisyon davranışı'
  });
}

// Toplam risk skoru hesapla
const totalRisk = anomalies.reduce((sum, a) => sum + (a.severity === 'HIGH' ? 30 : a.severity === 'MEDIUM' ? 15 : 5) * a.confidence, 0);
const riskScore = Math.min(100, Math.round(totalRisk));

let riskLevel = 'LOW';
if (riskScore >= 70) riskLevel = 'CRITICAL';
else if (riskScore >= 50) riskLevel = 'HIGH';
else if (riskScore >= 30) riskLevel = 'MEDIUM';

return [{
  json: {
    sessionId: data.sessionId,
    riskScore,
    riskLevel,
    anomalies,
    anomalyCount: anomalies.length,
    customerId: data.customerId,
    timestamp: data.timestamp,
    action: riskLevel === 'CRITICAL' ? 'BLOCK' : riskLevel === 'HIGH' ? 'ALERT' : riskLevel === 'MEDIUM' ? 'WARN' : 'OK'
  }
}];

